void DMA1_Stream5_IRQHandler(void) {
    // 1. 检查传输完成中断标志
    if (__HAL_DMA_GET_FLAG(&hdma_usart1_rx, DMA_FLAG_TCIF1_5)) {
        // 2. 清除标志位，避免重复进入中断
        __HAL_DMA_CLEAR_FLAG(&hdma_usart1_rx, DMA_FLAG_TCIF1_5);

        // 3. 计算已接收的数据大小
        uint32_t current_pos = hdma_usart1_rx.Instance->NDTR;
        ring_buffer.tail = (RING_BUFFER_SIZE - current_pos) % RING_BUFFER_SIZE;

        // 4. 通知上层有新数据
        Notify_Data_Ready();
    }
}

/* 使用 __attribute__((aligned(32))) 确保 buffer 对齐 */
uint8_t rx_buffer[128] __attribute__((aligned(32)));

/* 在读写操作前执行 Cache 清除或无效操作 */
SCB_InvalidateDCache_by_Addr((uint32_t *)rx_buffer, 128);

/* 改进前：直接操作 */
extern uint8_t g_buf[10];
