/* 改进后：封装访问器 */
int RingBuffer_Push(RingBuffer_t *rb, uint8_t data) {
    size_t next = (rb->head + 1) % rb->size;
    if (next == rb->tail) return -1; // 缓冲区满
    rb->buffer[rb->head] = data;
    rb->head = next;
    return 0;
}
